const fs = require('fs');

function repairFile(file) {
    if (!fs.existsSync(file)) return;
    let text = fs.readFileSync(file, 'utf8');

    // Fix Powershell interpolation breaking
    text = text.replace(/Bs\. \{/g, '${');

    // Fix extra Bs generated by string interpolation
    text = text.replace(/Bs\. \$\{/g, '${');

    // Fix text corruptions found in POS
    let map = {
        'Gestin': 'Gestión',
        'rpida': 'rápida',
        'MEN': 'MENÚ',
        'categora': 'categoría',
        'tem': 'ítem',
        'ira': 'iría',
        'ac': 'acá',
        'Envo': 'Envío',
        'fall': 'falló',
        'rpido': 'rápido',
        'PPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPPP': '═══════════════════════════════════════════════════════════',
        '<~': '🍾',
        'L Error': '❌ Error',
        '  Vendido!': '✓ ¡Vendido!',
        'categora': 'categoría',
        '': 'á', // Usually replacing diamond with 'a' or similar, but let's not blindly do it
    };

    for (let k in map) {
        text = text.split(k).join(map[k]);
    }

    fs.writeFileSync(file, text);
    console.log('Repaired', file);
}

repairFile('public/pos.js');
repairFile('public/pos.html');
repairFile('public/planilla.html');
